INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1994, 210729, 6, 2088, '追忆似水年华', '我很不习惯白天坐在屏幕前写东西，首先感谢这场大雨，给电脑充了电。播着《黑色星期天》，不由自觉开始敲字。
<br>    
<br>    现实让我不敢展望未来，即便是偶尔的憧憬都让人感到奢侈。过去的16年如雪花飘似的无奇，能放进记忆里的除了外公的死就只剩下不能在一起的初恋。直到去年，才发觉到自己的渺小，深刻体会到外婆那句：“我吃过的盐比你吃过的饭还多。”的寓意。挫折会促使人长大，前天因为好奇无聊测测自己的精神年龄：35岁，老化程度47%。一看数字真是惊人，尽管我不信这一套，但觉得它至少说明了什么。小白看完这些数字就笑的在地上打滚，活像只求饶的丧家犬。我问，你丫的笑什么。小白说，得了吧你，丫的抽烟喝酒打牌泡妞你会几样，还在老子面前装老成。我听完后就恼了，你他爹的，除了抽烟喝酒打牌泡妞你还会几样，自己不学无术还管起老子来了。话完后就觉得后悔，不该刺到他的隐处，这回恐怕比拿起大炮朝他那里轰了一下还严重。下意识拿起瓶可乐递过去：兄弟吵架伤和气。低头望见他锤子般的拳头已经握的紧紧……
<br>
<br>    觉得生活真是百般无味，王硕说：“生活就像是在被强奸，当你无力反抗时，只好默莫地享受。”照我的观点：生活就像是在漏着水的脸盆里游泳。我可不敢像那些俗人一样教训大家：一定要接受现实啊，展望明天啊之类的。抑或像那类叛逆分子宣扬快乐主义，今朝有酒今朝醉。让我说这些倒不如宰了我，感觉真是有够做作。只是觉得有些事真不应该看得太透，留点神秘给自己，做只快乐的小猪未尝不可。生活的压力总是无形中自己抛给自己的，或许，我们真应该学会如何去过活。如匪哥那天说的，想混出个名堂：1，必须有钱。2，必须有权。3，必须有本事。摸摸只有几个铜板的口袋，唉声叹气自己命苦，我想只有第3点最现实。
<br>
<br>    雨开始变小，难得我有雅兴撑伞漫步在河边，1个半月的干旱让那条垃圾河已快到了底，今早的暴雨总算给它滋润了一下。看到河水缠绵地流畅，忽地记起昨天是7夕。我的爱情是悲惨的，没有爱的字眼，没有太多浪漫地成分，隐隐透着喜欢与喜欢。想想这样也好，不用担心和那些玩心跳的情侣一样，等感觉没了就立马分手。也许我的休止符会画得很长很长。16年前，我没想过这个节日。16年后，我想过却过不了。我有点反感她想约一大帮朋友一起过，她说，她两边都不想扔，情人节对她来说言，已没了吸引。我微笑着叫她自己去玩，想极力掩饰着那双酸溜溜的眼睛。她不在的时候，总会用仅有的思想去疯狂地想她。记得我曾答应要迁就她。这样，伤害得就只有自己。用手机从头到尾打完通讯录上的电话，有女朋友的：正在浪漫甜蜜着；失恋的：正抱着枕头痛哭；那些看完痞子蔡《第一次的亲密接触》头脑发热的：正在网上网罗着自己的“轻舞飞扬”……下午，约小白去打球，他说天太热死活不肯。我咬咬牙，一狠心。拿出一张偷拍他挖鼻屎的照片嚷着要给她女朋友。这回他才慌了，忙求着我住手，说这次兄弟上刀山下火海连眼睛都不眨一下。我一想到丫的这平时在镜子前打扮多过睡觉时间的家伙，这回栽在我手里，心里就特来劲。手术后，除了跑跑步就真得没什么活动可言。一起挥霍掉累积的青春，真是再畅快淋漓不过了。两人坐下来狂饮着雪碧的快感，又该追溯到哪一天呢？
<br>
<br>    遮开窗帘，雨仍然下着，替我的心情涂满了乌云。我想，我的雨天还要继续，生活，真他爹的像在漏水的脸盆里打滚！', '我很不习惯白天坐在屏幕前写东西，首先感谢这场大雨，给电脑充了电。播着《黑色星期天》，不由自觉开始敲字。

现实让我不敢展望未来，即便是偶尔的憧憬都让人感到奢侈。过去的16年如雪花飘似的无奇，能放进记忆里的除了外公的死就只剩下不能在一起的初恋。直到去年，才发觉到自己的渺小，深刻体会到外婆那句：“我吃过的盐比你吃过的饭还多。”的寓意。挫折会促使人长大，前天因为好奇无聊测测自己的精神年龄：35岁，老化程度47%。一看数字真是惊人，尽管我不信这一套，但觉得它至少说明了什么。小白看完这些数字就笑的在地上打滚，活像只求饶的丧家犬。我问，你丫的笑什么。小白说，得了吧你，丫的抽烟喝酒打牌泡妞你会几样，还在老子面前装老成。我听完后就恼了，你他爹的，除了抽烟喝酒打牌泡妞你还会几样，自己不学无术还管起老子来了。话完后就觉得后悔，不该刺到他的隐处，这回恐怕比拿起大炮朝他那里轰了一下还严重。下意识拿起瓶可乐递过去：兄弟吵架伤和气。低头望见他锤子般的拳头已经握的紧紧……

觉得生活真是百般无味，王硕说：“生活就像是在被强奸，当你无力反抗时，只好默莫地享受。”照我的观点：生活就像是在漏着水的脸盆里游泳。我可不敢像那些俗人一样教训大家：一定要接受现实啊，展望明天啊之类的。抑或像那类叛逆分子宣扬快乐主义，今朝有酒今朝醉。让我说这些倒不如宰了我，感觉真是有够做作。只是觉得有些事真不应该看得太透，留点神秘给自己，做只快乐的小猪未尝不可。生活的压力总是无形中自己抛给自己的，或许，我们真应该学会如何去过活。如匪哥那天说的，想混出个名堂：1，必须有钱。2，必须有权。3，必须有本事。摸摸只有几个铜板的口袋，唉声叹气自己命苦，我想只有第3点最现实。

雨开始变小，难得我有雅兴撑伞漫步在河边，1个半月的干旱让那条垃圾河已快到了底，今早的暴雨总算给它滋润了一下。看到河水缠绵地流畅，忽地记起昨天是7夕。我的爱情是悲惨的，没有爱的字眼，没有太多浪漫地成分，隐隐透着喜欢与喜欢。想想这样也好，不用担心和那些玩心跳的情侣一样，等感觉没了就立马分手。也许我的休止符会画得很长很长。16年前，我没想过这个节日。16年后，我想过却过不了。我有点反感她想约一大帮朋友一起过，她说，她两边都不想扔，情人节对她来说言，已没了吸引。我微笑着叫她自己去玩，想极力掩饰着那双酸溜溜的眼睛。她不在的时候，总会用仅有的思想去疯狂地想她。记得我曾答应要迁就她。这样，伤害得就只有自己。用手机从头到尾打完通讯录上的电话，有女朋友的：正在浪漫甜蜜着；失恋的：正抱着枕头痛哭；那些看完痞子蔡《第一次的亲密接触》头脑发热的：正在网上网罗着自己的“轻舞飞扬”……下午，约小白去打球，他说天太热死活不肯。我咬咬牙，一狠心。拿出一张偷拍他挖鼻屎的照片嚷着要给她女朋友。这回他才慌了，忙求着我住手，说这次兄弟上刀山下火海连眼睛都不眨一下。我一想到丫的这平时在镜子前打扮多过睡觉时间的家伙，这回栽在我手里，心里就特来劲。手术后，除了跑跑步就真得没什么活动可言。一起挥霍掉累积的青春，真是再畅快淋漓不过了。两人坐下来狂饮着雪碧的快感，又该追溯到哪一天呢？

遮开窗帘，雨仍然下着，替我的心情涂满了乌云。我想，我的雨天还要继续，生活，真他爹的像在漏水的脸盆里打滚！', NULL, '2003-08-05 09:48:00', 5, '20030808075523_bbsid_210729_board_6_2644a85e7e.html', '20030808075523');
